/**
 * Classe de base pour toutes les erreurs du SDK CinetPay.
 * Toutes les erreurs du SDK héritent de cette classe, ce qui permet
 * un catch-all simple : `catch (e) { if (e instanceof CinetPayError) ... }`
 */
export class CinetPayError extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'CinetPayError'
  }
}
