/** Informations de l'utilisateur dans une notification webhook */
export interface WebhookUser {
  /** Nom complet de l'utilisateur */
  name: string
  /** Adresse e-mail de l'utilisateur */
  email: string
  /** Numéro de téléphone de l'utilisateur */
  phoneNumber: string
}

/**
 * Payload d'une notification webhook envoyée par CinetPay.
 * Reçu en POST sur votre `notifyUrl` quand une transaction atteint un statut final.
 */
export interface WebhookPayload {
  /** Token de notification — à comparer avec celui reçu lors de l'initialisation */
  notifyToken: string
  /** Identifiant de la transaction côté marchand */
  merchantTransactionId: string
  /** Identifiant unique de la transaction CinetPay */
  transactionId: string
  /** Informations sur l'utilisateur (peut être absent) */
  user?: WebhookUser
}

/** @internal Transforme le body brut du webhook en WebhookPayload typé */
export function toWebhookPayload(raw: Record<string, unknown>): WebhookPayload {
  const user = raw.user as Record<string, unknown> | undefined
  return {
    notifyToken: raw.notify_token as string,
    merchantTransactionId: raw.merchant_transaction_id as string,
    transactionId: raw.transaction_id as string,
    ...(user && {
      user: {
        name: user.name as string,
        email: user.email as string,
        phoneNumber: user.phone_number as string,
      },
    }),
  }
}
