import type { Logger } from '../logger'
import { ApiError } from '../errors/api-error'
import { NetworkError, TimeoutError } from '../errors/index'

/**
 * Client HTTP interne — wrapper autour de `fetch` natif.
 * Gère les headers, le timeout via AbortController, et le mapping des erreurs API.
 * @internal
 */
export class HttpClient {
  constructor(
    private readonly baseUrl: string,
    private readonly timeout: number,
    private readonly logger: Logger,
  ) {
    if (typeof globalThis.fetch === 'undefined') {
      throw new Error(
        'fetch is not available in this environment. Use Node.js 18+ or provide a fetch polyfill.',
      )
    }
  }

  /** Effectue une requête POST et retourne la réponse parsée */
  async post<T>(
    path: string,
    body: unknown,
    token?: string,
  ): Promise<T> {
    return this.request<T>('POST', path, body, token)
  }

  /** Effectue une requête GET et retourne la réponse parsée */
  async get<T>(path: string, token?: string): Promise<T> {
    return this.request<T>('GET', path, undefined, token)
  }

  private async request<T>(
    method: string,
    path: string,
    body?: unknown,
    token?: string,
  ): Promise<T> {
    const url = `${this.baseUrl}${path}`
    const controller = new AbortController()
    const timeoutId = setTimeout(() => controller.abort(), this.timeout)

    const headers: Record<string, string> = {
      Accept: 'application/json',
      'Content-Type': 'application/json',
    }
    if (token) {
      headers.Authorization = `Bearer ${token}`
    }

    this.logger.debug(`${method} ${path}`, {
      ...(body ? { body: this.sanitizeBody(body) } : {}),
    })

    try {
      const response = await globalThis.fetch(url, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      })

      const data = (await response.json()) as Record<string, unknown>

      this.logger.debug(`${method} ${path} → ${response.status}`, {
        code: data.code as number,
        status: data.status as string,
      })

      return this.handleResponse<T>(data, response.status, method, path)
    } catch (error: unknown) {
      if (error instanceof ApiError) throw error
      if (
        error instanceof DOMException &&
        error.name === 'AbortError'
      ) {
        this.logger.error(`${method} ${path} → timeout (${this.timeout}ms)`)
        throw new TimeoutError(this.timeout)
      }
      this.logger.error(`${method} ${path} → network error`, {
        message: error instanceof Error ? error.message : String(error),
      })
      throw new NetworkError(
        `Request to ${method} ${path} failed`,
        error,
      )
    } finally {
      clearTimeout(timeoutId)
    }
  }

  private handleResponse<T>(
    data: Record<string, unknown>,
    httpStatus: number,
    method: string,
    path: string,
  ): T {
    const code = data.code as number | undefined

    if (
      httpStatus >= 400 ||
      (code !== undefined && code !== 200 && code !== 100 && code !== 2001 && code !== 2002)
    ) {
      if (data.description || (code !== undefined && httpStatus >= 400)) {
        const error = ApiError.fromResponse(data)
        this.logger.error(`${method} ${path} → API error`, {
          apiCode: error.apiCode,
          apiStatus: error.apiStatus,
          description: error.description,
        })
        throw error
      }
    }

    return data as T
  }

  /** Masque les champs sensibles (credentials, tokens) dans les logs */
  private sanitizeBody(body: unknown): unknown {
    if (typeof body !== 'object' || body === null) return body
    const sanitized = { ...(body as Record<string, unknown>) }
    for (const key of Object.keys(sanitized)) {
      const lower = key.toLowerCase()
      if (
        lower.includes('password') ||
        lower.includes('secret') ||
        lower.includes('token') ||
        (lower.includes('key') && lower.includes('api'))
      ) {
        sanitized[key] = '***'
      }
    }
    return sanitized
  }
}
