/**
 * Statuts de transaction possibles dans l'API CinetPay.
 *
 * @example
 * ```typescript
 * import { TRANSACTION_STATUSES } from 'cinetpay-js'
 * if (status === TRANSACTION_STATUSES.SUCCESS) { ... }
 * ```
 */
export const TRANSACTION_STATUSES = {
  /** Opération réussie (réponse API, pas un statut final de transaction) */
  OK: 'OK',
  /** Transaction traitée avec succès — statut final */
  SUCCESS: 'SUCCESS',
  /** Une erreur s'est produite */
  OPERATION_ERROR: 'OPERATION_ERROR',
  /** Ressource introuvable */
  NOT_FOUND: 'NOT_FOUND',
  /** Identifiants API invalides */
  INVALID_CREDENTIALS: 'INVALID_CREDENTIALS',
  /** Paramètres de requête invalides */
  INVALID_PARAMS: 'INVALID_PARAMS',
  /** Token JWT expiré (le SDK gère le renouvellement automatiquement) */
  EXPIRED_TOKEN: 'EXPIRED_TOKEN',
  /** Token JWT invalide */
  INVALID_TOKEN: 'INVALID_TOKEN',
  /** La transaction existe déjà (merchant_transaction_id dupliqué) — statut final */
  TRANSACTION_EXIST: 'TRANSACTION_EXIST',
  /** Transaction initiée, en attente d'action de l'utilisateur */
  INITIATED: 'INITIATED',
  /** L'utilisateur a commencé le processus de paiement */
  PENDING: 'PENDING',
  /** Transaction expirée (l'utilisateur n'a pas confirmé) */
  EXPIRED: 'EXPIRED',
  /** Code OTP incorrect */
  OTP_ERROR: 'OTP_ERROR',
  /** Code OTP expiré */
  OTP_EXPIRED: 'OTP_EXPIRED',
  /** Solde marchand insuffisant — statut final */
  INSUFFICIENT_BALANCE: 'INSUFFICIENT_BALANCE',
  /** Utilisateur introuvable */
  USER_NOT_FOUND: 'USER_NOT_FOUND',
  /** Utilisateur bloqué */
  USER_IS_BLOCKED: 'USER_IS_BLOCKED',
  /** Paiement échoué — statut final */
  FAILED: 'FAILED',
  /** IP non autorisée (whitelist) */
  NOT_ALLOWED: 'NOT_ALLOWED',
} as const

/** Union des statuts de transaction */
export type TransactionStatus =
  (typeof TRANSACTION_STATUSES)[keyof typeof TRANSACTION_STATUSES]

const FINAL_STATUSES: ReadonlySet<string> = new Set([
  'SUCCESS',
  'FAILED',
  'TRANSACTION_EXIST',
  'INSUFFICIENT_BALANCE',
])

/**
 * Vérifie si un statut de transaction est final (plus de changement possible).
 * Les statuts finaux sont : SUCCESS, FAILED, TRANSACTION_EXIST, INSUFFICIENT_BALANCE.
 *
 * @param status - Statut à vérifier
 * @returns `true` si le statut est final
 *
 * @example
 * ```typescript
 * import { isFinalStatus } from 'cinetpay-js'
 *
 * isFinalStatus('SUCCESS') // true
 * isFinalStatus('PENDING') // false
 * ```
 */
export function isFinalStatus(status: string): boolean {
  return FINAL_STATUSES.has(status)
}

/**
 * Table de correspondance entre les codes numériques API et les statuts textuels.
 *
 * @example
 * ```typescript
 * import { API_CODES } from 'cinetpay-js'
 * API_CODES[100]  // 'SUCCESS'
 * API_CODES[2010] // 'FAILED'
 * ```
 */
export const API_CODES: Record<number, TransactionStatus> = {
  200: 'OK',
  100: 'SUCCESS',
  [-1]: 'OPERATION_ERROR',
  404: 'NOT_FOUND',
  1005: 'INVALID_CREDENTIALS',
  1004: 'INVALID_PARAMS',
  1003: 'EXPIRED_TOKEN',
  1002: 'INVALID_TOKEN',
  1200: 'TRANSACTION_EXIST',
  2001: 'INITIATED',
  2002: 'PENDING',
  2003: 'EXPIRED',
  2004: 'OTP_ERROR',
  2008: 'OTP_EXPIRED',
  2005: 'INSUFFICIENT_BALANCE',
  2006: 'USER_NOT_FOUND',
  2007: 'USER_IS_BLOCKED',
  2010: 'FAILED',
  2011: 'NOT_ALLOWED',
}

/** Codes pays supportés par CinetPay */
export const COUNTRY_CODES = [
  'CI',
  'BF',
  'ML',
  'SN',
  'TG',
  'GN',
  'CM',
  'BJ',
  'CD',
  'NE',
] as const

/** Union des codes pays */
export type CountryCode = (typeof COUNTRY_CODES)[number]
