import type { Currency } from '../constants/currencies'
import type { Channel } from '../constants/channels'
import type { PaymentMethod } from '../constants/payment-methods'
import type { TransactionStatus } from '../constants/statuses'

/**
 * Paramètres pour initialiser un paiement web via `client.payment.initialize()`.
 *
 * @see https://docs.cinetpay.com — POST /v1/payment
 */
export interface PaymentRequest {
  /** Devise de paiement : XOF, XAF, GNF, CDF ou USD */
  currency: Currency
  /** Identifiant unique de la transaction côté marchand (max 30 caractères) */
  merchantTransactionId: string
  /** Montant du paiement (min: 100, max: 2 500 000) */
  amount: number
  /** Langue de l'interface de paiement */
  lang: 'fr' | 'en'
  /** Libellé du paiement affiché au client */
  designation: string
  /** Adresse e-mail du client (doit être valide) */
  clientEmail: string
  /** Prénom du client (2-255 caractères) */
  clientFirstName: string
  /** Nom du client (2-255 caractères) */
  clientLastName: string
  /** URL de redirection après un paiement réussi (max 120 caractères) */
  successUrl: string
  /** URL de redirection après un paiement échoué (max 120 caractères) */
  failedUrl: string
  /** URL de notification webhook pour le statut final (max 120 caractères) */
  notifyUrl: string
  /** Canal de paiement : PUSH (notification), OTP (code) ou QRCODE */
  channel: Channel
  /**
   * Méthode de paiement spécifique (ex: OM_CI, WAVE_SN).
   * Si omis, toutes les méthodes du pays sont proposées.
   */
  paymentMethod?: PaymentMethod
  /**
   * Numéro de téléphone du client au format international (ex: +2250707000000).
   * Obligatoire si `directPay` est activé.
   */
  clientPhoneNumber?: string
  /**
   * Active le mode paiement direct (sans redirection vers la passerelle CinetPay).
   * Nécessite `paymentMethod`, `clientPhoneNumber`, et éventuellement `otpCode`.
   */
  directPay?: boolean
  /** Code OTP fourni par le client (4-6 chiffres, requis pour Orange Money en mode direct) */
  otpCode?: string
}

/** Détails du statut de paiement direct retournés dans la réponse d'initialisation */
export interface PaymentDetails {
  /** Code numérique du statut */
  code: number
  /** Statut textuel : SUCCESS, FAILED, INITIATED ou PENDING */
  status: TransactionStatus
  /** Message à afficher à l'utilisateur */
  message: string
  /**
   * Indique si le client doit être redirigé vers `paymentUrl`.
   * `true` pour les paiements classiques, `false` si le paiement direct a abouti.
   */
  mustBeRedirected: boolean
}

/** Réponse retournée après l'initialisation d'un paiement */
export interface PaymentResponse {
  /** Code HTTP de la réponse API */
  code: number
  /** Statut textuel de la réponse */
  status: string
  /** Token unique du paiement (utilisable pour vérifier le statut) */
  paymentToken: string
  /** Token de notification (à conserver pour vérifier les webhooks) */
  notifyToken: string
  /** Identifiant unique de la transaction CinetPay */
  transactionId: string
  /** Identifiant de la transaction côté marchand */
  merchantTransactionId: string
  /** URL de la passerelle de paiement (rediriger le client vers cette URL) */
  paymentUrl: string
  /** Détails du paiement direct (statut, message, redirection) */
  details: PaymentDetails
}

/** Informations de l'utilisateur retournées dans le statut d'un paiement */
export interface PaymentStatusUser {
  /** Nom complet de l'utilisateur */
  name: string
  /** Adresse e-mail de l'utilisateur */
  email: string
  /** Numéro de téléphone de l'utilisateur */
  phoneNumber: string
}

/** Statut d'un paiement retourné par `client.payment.getStatus()` */
export interface PaymentStatus {
  /** Code numérique du statut (100 = SUCCESS, 2010 = FAILED, etc.) */
  code: number
  /** Statut textuel de la transaction */
  status: TransactionStatus
  /** Identifiant de la transaction côté marchand */
  merchantTransactionId: string
  /** Identifiant unique de la transaction CinetPay */
  transactionId: string
  /** Informations sur l'utilisateur ayant effectué le paiement */
  user: PaymentStatusUser
}

/** @internal Sérialise un PaymentRequest (camelCase) vers le format API (snake_case) */
export function serializePaymentRequest(
  req: PaymentRequest,
): Record<string, unknown> {
  const body: Record<string, unknown> = {
    currency: req.currency,
    merchant_transaction_id: req.merchantTransactionId,
    amount: req.amount,
    lang: req.lang,
    designation: req.designation,
    client_email: req.clientEmail,
    client_first_name: req.clientFirstName,
    client_last_name: req.clientLastName,
    success_url: req.successUrl,
    failed_url: req.failedUrl,
    notify_url: req.notifyUrl,
    channel: req.channel,
  }
  if (req.paymentMethod !== undefined) body.payment_method = req.paymentMethod
  if (req.clientPhoneNumber !== undefined)
    body.client_phone_number = req.clientPhoneNumber
  if (req.directPay !== undefined) body.direct_pay = req.directPay
  if (req.otpCode !== undefined) body.otp_code = req.otpCode
  return body
}

/** @internal Transforme la réponse brute API en PaymentResponse typé */
export function toPaymentResponse(raw: Record<string, unknown>): PaymentResponse {
  const details = raw.details as Record<string, unknown> | undefined
  return {
    code: raw.code as number,
    status: raw.status as string,
    paymentToken: raw.payment_token as string,
    notifyToken: raw.notify_token as string,
    transactionId: raw.transaction_id as string,
    merchantTransactionId: raw.merchant_transaction_id as string,
    paymentUrl: raw.payment_url as string,
    details: details
      ? {
          code: details.code as number,
          status: details.status as TransactionStatus,
          message: details.message as string,
          mustBeRedirected: details.must_be_redirected as boolean,
        }
      : { code: 0, status: 'INITIATED', message: '', mustBeRedirected: false },
  }
}

/** @internal Transforme la réponse brute API en PaymentStatus typé */
export function toPaymentStatus(raw: Record<string, unknown>): PaymentStatus {
  const user = raw.user as Record<string, unknown> | undefined
  return {
    code: raw.code as number,
    status: raw.status as TransactionStatus,
    merchantTransactionId: raw.merchant_transaction_id as string,
    transactionId: raw.transaction_id as string,
    user: user
      ? {
          name: user.name as string,
          email: user.email as string,
          phoneNumber: user.phone_number as string,
        }
      : { name: '', email: '', phoneNumber: '' },
  }
}
