import type { WebhookPayload } from '../types/webhook'
import { toWebhookPayload } from '../types/webhook'

/**
 * Vérifie l'authenticité d'une notification webhook en comparant les tokens
 * de manière timing-safe (résistante aux attaques par timing).
 *
 * **Usage côté serveur uniquement.**
 *
 * @param expectedToken - Le `notifyToken` reçu lors de l'initialisation du paiement/transfert
 * @param receivedToken - Le `notify_token` reçu dans le body du webhook
 * @returns `true` si les tokens correspondent
 *
 * @example
 * ```typescript
 * import { verifyNotification } from 'cinetpay-js'
 *
 * const isValid = verifyNotification(storedNotifyToken, notification.notifyToken)
 * if (!isValid) {
 *   return res.status(401).send('Invalid token')
 * }
 * ```
 */
export function verifyNotification(
  expectedToken: string,
  receivedToken: string,
): boolean {
  if (expectedToken.length !== receivedToken.length) return false

  let result = 0
  for (let i = 0; i < expectedToken.length; i++) {
    result |= expectedToken.charCodeAt(i) ^ receivedToken.charCodeAt(i)
  }
  return result === 0
}

/**
 * Parse le body brut d'une notification webhook CinetPay en un objet typé.
 * Accepte un objet JSON déjà parsé ou une chaîne JSON.
 *
 * @param body - Body de la requête webhook (objet ou chaîne JSON)
 * @returns Payload typé avec `notifyToken`, `transactionId`, `merchantTransactionId` et optionnellement `user`
 * @throws {TypeError} Si le body ne contient pas `notify_token` ou `transaction_id`
 *
 * @example
 * ```typescript
 * import { parseNotification } from 'cinetpay-js'
 *
 * // Express
 * app.post('/webhook', (req, res) => {
 *   const notification = parseNotification(req.body)
 *   console.log(notification.transactionId)
 * })
 * ```
 */
export function parseNotification(
  body: unknown,
): WebhookPayload {
  const data =
    typeof body === 'string'
      ? (JSON.parse(body) as Record<string, unknown>)
      : (body as Record<string, unknown>)

  if (!data.notify_token || !data.transaction_id) {
    throw new TypeError(
      'Invalid webhook payload: missing notify_token or transaction_id',
    )
  }

  return toWebhookPayload(data)
}
