/**
 * Interface de logging injectable.
 * Implémentez cette interface pour utiliser votre propre logger (Winston, Pino, etc.).
 *
 * @example
 * ```typescript
 * import pino from 'pino'
 *
 * const pinoLogger = pino()
 * const client = new CinetPayClient({
 *   credentials: { ... },
 *   logger: {
 *     debug: (msg, data) => pinoLogger.debug(data, msg),
 *     warn: (msg, data) => pinoLogger.warn(data, msg),
 *     error: (msg, data) => pinoLogger.error(data, msg),
 *   },
 * })
 * ```
 */
export interface Logger {
  /** Détails des requêtes/réponses, tokens cachés, etc. */
  debug(message: string, data?: Record<string, unknown>): void
  /** Retry sur token expiré, fallbacks */
  warn(message: string, data?: Record<string, unknown>): void
  /** Erreurs API, réseau, timeout */
  error(message: string, data?: Record<string, unknown>): void
}

/**
 * Logger qui écrit dans `console` avec un préfixe `[cinetpay]`.
 * Utilisé quand `debug: true` est passé sans logger custom.
 */
export class ConsoleLogger implements Logger {
  debug(message: string, data?: Record<string, unknown>): void {
    console.debug(`[cinetpay] ${message}`, data ?? '')
  }
  warn(message: string, data?: Record<string, unknown>): void {
    console.warn(`[cinetpay] ${message}`, data ?? '')
  }
  error(message: string, data?: Record<string, unknown>): void {
    console.error(`[cinetpay] ${message}`, data ?? '')
  }
}

/** Logger silencieux — ne produit aucune sortie. Utilisé par défaut. */
export class NoopLogger implements Logger {
  debug(): void {}
  warn(): void {}
  error(): void {}
}
