import type { Currency } from '../constants/currencies'
import type { PaymentMethod } from '../constants/payment-methods'
import type { TransactionStatus } from '../constants/statuses'

/**
 * Paramètres pour effectuer un transfert d'argent via `client.transfer.create()`.
 *
 * @see https://docs.cinetpay.com — POST /v1/transfer
 */
export interface TransferRequest {
  /** Devise du transfert. Doit correspondre à la devise du compte marchand. */
  currency: Currency
  /** Identifiant unique de la transaction côté marchand */
  merchantTransactionId: string
  /** Numéro de téléphone du bénéficiaire au format international (ex: +2250707000001) */
  phoneNumber: string
  /** Montant du transfert (min: 500, max: 1 500 000) */
  amount: number
  /** Méthode de paiement/opérateur (ex: OM_CI, WAVE_SN) */
  paymentMethod: PaymentMethod
  /** Motif du transfert */
  reason: string
  /** URL de notification webhook pour le statut final du transfert */
  notifyUrl: string
}

/** Réponse retournée après la création d'un transfert */
export interface TransferResponse {
  /** Code numérique de la réponse API */
  code: number
  /** Statut de la transaction (PENDING, SUCCESS, FAILED) */
  status: TransactionStatus
  /** Identifiant de la transaction côté marchand */
  merchantTransactionId: string
  /** Identifiant unique de la transaction CinetPay */
  transactionId: string
  /** Token de notification (à conserver pour vérifier les webhooks) */
  notifyToken: string
  /** Montant du transfert */
  amount: string
  /** Montant des frais appliqués */
  feeAmount: string
  /** Numéro de téléphone du bénéficiaire */
  phoneNumber: string
  /** Devise du transfert */
  currency: Currency
}

/** Informations de l'utilisateur retournées dans le statut d'un transfert */
export interface TransferStatusUser {
  /** Nom complet de l'utilisateur */
  name: string
  /** Adresse e-mail de l'utilisateur */
  email: string
  /** Numéro de téléphone de l'utilisateur */
  phoneNumber: string
}

/** Statut d'un transfert retourné par `client.transfer.getStatus()` */
export interface TransferStatus {
  /** Code numérique du statut (100 = SUCCESS, 2010 = FAILED, etc.) */
  code: number
  /** Statut textuel de la transaction */
  status: TransactionStatus
  /** Identifiant de la transaction côté marchand */
  merchantTransactionId: string
  /** Identifiant unique de la transaction CinetPay */
  transactionId: string
  /** Montant du transfert */
  amount: string
  /** Montant des frais appliqués */
  feeAmount: string
  /** Informations sur le bénéficiaire */
  user?: TransferStatusUser
  /** Numéro de téléphone du bénéficiaire */
  phoneNumber?: string
  /** Devise du transfert */
  currency?: Currency
}

/** @internal Sérialise un TransferRequest (camelCase) vers le format API (snake_case) */
export function serializeTransferRequest(
  req: TransferRequest,
): Record<string, unknown> {
  return {
    currency: req.currency,
    merchant_transaction_id: req.merchantTransactionId,
    phone_number: req.phoneNumber,
    amount: req.amount,
    payment_method: req.paymentMethod,
    reason: req.reason,
    notify_url: req.notifyUrl,
  }
}

/** @internal Transforme la réponse brute API en TransferResponse typé */
export function toTransferResponse(
  raw: Record<string, unknown>,
): TransferResponse {
  return {
    code: raw.code as number,
    status: raw.status as TransactionStatus,
    merchantTransactionId: raw.merchant_transaction_id as string,
    transactionId: raw.transaction_id as string,
    notifyToken: raw.notify_token as string,
    amount: String(raw.amount),
    feeAmount: String(raw.fee_amount),
    phoneNumber: raw.phone_number as string,
    currency: raw.currency as Currency,
  }
}

/** @internal Transforme la réponse brute API en TransferStatus typé */
export function toTransferStatus(
  raw: Record<string, unknown>,
): TransferStatus {
  const user = raw.user as Record<string, unknown> | undefined
  const result: TransferStatus = {
    code: raw.code as number,
    status: raw.status as TransactionStatus,
    merchantTransactionId: raw.merchant_transaction_id as string,
    transactionId: raw.transaction_id as string,
    amount: String(raw.amount),
    feeAmount: String(raw.fee_amount),
  }
  if (user) {
    result.user = {
      name: user.name as string,
      email: user.email as string,
      phoneNumber: user.phone_number as string,
    }
  }
  if (raw.phone_number) result.phoneNumber = raw.phone_number as string
  if (raw.currency) result.currency = raw.currency as Currency
  return result
}
