/**
 * Devises supportées par l'API CinetPay.
 *
 * @example
 * ```typescript
 * import { CURRENCIES } from 'cinetpay-js'
 * const currency = CURRENCIES.XOF // 'XOF'
 * ```
 */
export const CURRENCIES = {
  /** Franc CFA BCEAO (Afrique de l'Ouest) */
  XOF: 'XOF',
  /** Franc CFA BEAC (Afrique Centrale) */
  XAF: 'XAF',
  /** Franc guinéen */
  GNF: 'GNF',
  /** Franc congolais */
  CDF: 'CDF',
  /** Dollar américain */
  USD: 'USD',
} as const

/** Union des codes devise supportés */
export type Currency = (typeof CURRENCIES)[keyof typeof CURRENCIES]
