import type { TokenStore } from '../types/config'

/** @internal Structure d'une entrée en cache */
interface CacheEntry {
  /** Valeur du token */
  value: string
  /** Timestamp d'expiration en millisecondes (Date.now() + ttl * 1000) */
  expiresAt: number
}

/**
 * Store de tokens en mémoire (implémentation par défaut).
 * Les tokens expirés sont automatiquement supprimés à la lecture (éviction paresseuse).
 *
 * Adapté pour un processus unique. Pour la production multi-instances,
 * implémentez {@link TokenStore} avec Redis ou un autre backend partagé.
 *
 * @example
 * ```typescript
 * import { MemoryTokenStore } from 'cinetpay-js'
 * const store = new MemoryTokenStore()
 * ```
 */
export class MemoryTokenStore implements TokenStore {
  private cache = new Map<string, CacheEntry>()

  /**
   * Récupère un token depuis le cache.
   * Si le token est expiré, il est supprimé et `null` est retourné.
   *
   * @param key - Clé de cache (ex: `cinetpay_token_ci`)
   * @returns Le token ou `null` s'il est absent/expiré
   */
  get(key: string): string | null {
    const entry = this.cache.get(key)
    if (!entry) return null
    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(key)
      return null
    }
    return entry.value
  }

  /**
   * Stocke un token avec une durée de vie.
   *
   * @param key - Clé de cache
   * @param value - Token JWT
   * @param ttlSeconds - Durée de vie en secondes
   */
  set(key: string, value: string, ttlSeconds: number): void {
    this.cache.set(key, {
      value,
      expiresAt: Date.now() + ttlSeconds * 1000,
    })
  }

  /**
   * Supprime un token du cache.
   *
   * @param key - Clé de cache à supprimer
   */
  delete(key: string): void {
    this.cache.delete(key)
  }
}
