import { CinetPayError } from './cinetpay-error'

/**
 * Erreur retournée par l'API CinetPay (code + statut + description).
 *
 * @example
 * ```typescript
 * try {
 *   await client.payment.initialize(request, 'CI')
 * } catch (error) {
 *   if (error instanceof ApiError) {
 *     console.log(error.apiCode)    // 1200
 *     console.log(error.apiStatus)  // 'TRANSACTION_EXIST'
 *     console.log(error.description) // 'La transaction existe déjà'
 *   }
 * }
 * ```
 */
export class ApiError extends CinetPayError {
  /** Code numérique de l'erreur API (ex: 1005, 1200, 2010) */
  readonly apiCode: number
  /** Statut textuel de l'erreur (ex: INVALID_CREDENTIALS, TRANSACTION_EXIST) */
  readonly apiStatus: string
  /** Description détaillée de l'erreur */
  readonly description: string

  constructor(apiCode: number, apiStatus: string, description: string) {
    super(`[${apiCode}] ${apiStatus}: ${description}`)
    this.name = 'ApiError'
    this.apiCode = apiCode
    this.apiStatus = apiStatus
    this.description = description
  }

  /**
   * Construit une ApiError à partir d'une réponse brute de l'API.
   * @internal
   */
  static fromResponse(data: Record<string, unknown>): ApiError {
    return new ApiError(
      (data.code as number) ?? 0,
      (data.status as string) ?? 'UNKNOWN',
      (data.description as string) ?? (data.message as string) ?? '',
    )
  }
}
