import { CinetPayError } from './cinetpay-error'

/**
 * Erreur d'authentification — les identifiants `api_key` / `api_password` sont invalides
 * ou l'API n'a pas retourné de token JWT.
 */
export class AuthenticationError extends CinetPayError {
  constructor(message: string = 'Authentication failed') {
    super(message)
    this.name = 'AuthenticationError'
  }
}
