/**
 * Canaux de paiement supportés par l'API CinetPay.
 *
 * @example
 * ```typescript
 * import { CHANNELS } from 'cinetpay-js'
 * const channel = CHANNELS.PUSH // Notification push
 * ```
 */
export const CHANNELS = {
  /** Notification push envoyée au téléphone du client */
  PUSH: 'PUSH',
  /** Code OTP saisi par le client */
  OTP: 'OTP',
  /** QR Code scanné par le client */
  QRCODE: 'QRCODE',
} as const

/** Union des canaux de paiement */
export type Channel = (typeof CHANNELS)[keyof typeof CHANNELS]
