export { ApiError } from './api-error'
export { AuthenticationError } from './authentication-error'

import { CinetPayError } from './cinetpay-error'

/**
 * Erreur réseau — la requête fetch a échoué (DNS, connexion refusée, etc.)
 *
 * @example
 * ```typescript
 * if (error instanceof NetworkError) {
 *   console.log(error.cause) // Erreur fetch originale
 * }
 * ```
 */
export class NetworkError extends CinetPayError {
  /** L'erreur originale qui a causé l'échec réseau */
  readonly cause: unknown

  constructor(message: string, cause?: unknown) {
    super(message)
    this.name = 'NetworkError'
    this.cause = cause
  }
}

/**
 * Erreur de timeout — la requête n'a pas reçu de réponse dans le délai imparti.
 * Configurable via `timeout` dans `ClientConfig` (défaut: 30 000ms).
 */
export class TimeoutError extends CinetPayError {
  constructor(timeoutMs: number) {
    super(`Request timed out after ${timeoutMs}ms`)
    this.name = 'TimeoutError'
  }
}
