/**
 * Méthodes de paiement (opérateurs mobile money) supportées par CinetPay.
 * Le format est `OPERATEUR_CODEPAYS` (ex: `OM_CI` = Orange Money Côte d'Ivoire).
 *
 * @example
 * ```typescript
 * import { PAYMENT_METHODS } from 'cinetpay-js'
 * const method = PAYMENT_METHODS.OM_CI // Orange Money CI
 * ```
 */
export const PAYMENT_METHODS = {
  // Côte d'Ivoire
  /** Orange Money — Côte d'Ivoire */
  OM_CI: 'OM_CI',
  /** Moov Money — Côte d'Ivoire */
  MOOV_CI: 'MOOV_CI',
  /** MTN Mobile Money — Côte d'Ivoire */
  MTN_CI: 'MTN_CI',
  /** Wave — Côte d'Ivoire */
  WAVE_CI: 'WAVE_CI',
  // Burkina Faso
  /** Orange Money — Burkina Faso */
  OM_BF: 'OM_BF',
  /** Moov Money — Burkina Faso */
  MOOV_BF: 'MOOV_BF',
  /** Wave — Burkina Faso */
  WAVE_BF: 'WAVE_BF',
  // Mali
  /** Orange Money — Mali */
  OM_ML: 'OM_ML',
  /** Moov Money — Mali */
  MOOV_ML: 'MOOV_ML',
  // Sénégal
  /** Orange Money — Sénégal */
  OM_SN: 'OM_SN',
  /** Free Money — Sénégal */
  FREE_SN: 'FREE_SN',
  /** Expresso — Sénégal */
  EXPRESSO_SN: 'EXPRESSO_SN',
  /** Wave — Sénégal */
  WAVE_SN: 'WAVE_SN',
  // Togo
  /** Moov Money — Togo */
  MOOV_TG: 'MOOV_TG',
  /** TMoney (Togocell) — Togo */
  TMONEY_TG: 'TMONEY_TG',
  // Guinée
  /** Orange Money — Guinée */
  OM_GN: 'OM_GN',
  /** MTN Mobile Money — Guinée */
  MTN_GN: 'MTN_GN',
  // Cameroun
  /** Orange Money — Cameroun */
  OM_CM: 'OM_CM',
  /** MTN Mobile Money — Cameroun */
  MTN_CM: 'MTN_CM',
  // Bénin
  /** Moov Money — Bénin */
  MOOV_BJ: 'MOOV_BJ',
  /** MTN Mobile Money — Bénin */
  MTN_BJ: 'MTN_BJ',
  // RD Congo
  /** Orange Money — RD Congo */
  OM_CD: 'OM_CD',
  /** Airtel Money — RD Congo */
  AIRTEL_CD: 'AIRTEL_CD',
  /** M-Pesa — RD Congo */
  MPESA_CD: 'MPESA_CD',
  /** Africell — RD Congo */
  AFRICELL_CD: 'AFRICELL_CD',
  // Niger
  /** Airtel Money — Niger */
  AIRTEL_NE: 'AIRTEL_NE',
  /** Moov Money — Niger */
  MOOV_NE: 'MOOV_NE',
  /** Zamani — Niger */
  ZAMANI_NE: 'ZAMANI_NE',
} as const

/** Union des codes de méthode de paiement */
export type PaymentMethod =
  (typeof PAYMENT_METHODS)[keyof typeof PAYMENT_METHODS]

/**
 * Méthodes de paiement groupées par code pays.
 * Utile pour afficher les opérateurs disponibles dans un formulaire.
 *
 * @example
 * ```typescript
 * import { PAYMENT_METHODS_BY_COUNTRY } from 'cinetpay-js'
 * console.log(PAYMENT_METHODS_BY_COUNTRY.CI)
 * // ['OM_CI', 'MOOV_CI', 'MTN_CI', 'WAVE_CI']
 * ```
 */
export const PAYMENT_METHODS_BY_COUNTRY = {
  CI: ['OM_CI', 'MOOV_CI', 'MTN_CI', 'WAVE_CI'],
  BF: ['OM_BF', 'MOOV_BF', 'WAVE_BF'],
  ML: ['OM_ML', 'MOOV_ML'],
  SN: ['OM_SN', 'FREE_SN', 'EXPRESSO_SN', 'WAVE_SN'],
  TG: ['MOOV_TG', 'TMONEY_TG'],
  GN: ['OM_GN', 'MTN_GN'],
  CM: ['OM_CM', 'MTN_CM'],
  BJ: ['MOOV_BJ', 'MTN_BJ'],
  CD: ['OM_CD', 'AIRTEL_CD', 'MPESA_CD', 'AFRICELL_CD'],
  NE: ['AIRTEL_NE', 'MOOV_NE', 'ZAMANI_NE'],
} as const satisfies Record<string, readonly PaymentMethod[]>
