import type { HttpClient } from '../http/http-client'
import type { Authenticator } from '../auth/authenticator'
import type {
  TransferRequest,
  TransferResponse,
  TransferStatus,
} from '../types/transfer'
import {
  serializeTransferRequest,
  toTransferResponse,
  toTransferStatus,
} from '../types/transfer'
import { ApiError } from '../errors/api-error'
import { validateTransferRequest } from '../validation'

/**
 * API de transfert d'argent CinetPay.
 * Permet d'envoyer de l'argent vers un numéro mobile money et de vérifier le statut.
 *
 * @example
 * ```typescript
 * // Accessible via client.transfer
 * const transfer = await client.transfer.create(request, 'CI')
 * const status = await client.transfer.getStatus(transfer.transactionId, 'CI')
 * ```
 */
export class TransferApi {
  constructor(
    private readonly httpClient: HttpClient,
    private readonly authenticators: Map<string, Authenticator>,
  ) {}

  /**
   * Effectue un transfert d'argent vers un numéro de téléphone.
   *
   * @param request - Paramètres du transfert (montant, devise, numéro, opérateur, etc.)
   * @param country - Code pays ISO (ex: 'CI', 'SN') — détermine les credentials utilisés
   * @returns Réponse contenant le statut initial et l'identifiant de transaction
   * @throws {ApiError} Si l'API retourne une erreur (ex: INSUFFICIENT_BALANCE, INVALID_PARAMS)
   * @throws {TypeError} Si le pays n'est pas configuré dans les credentials
   *
   * @example
   * ```typescript
   * const transfer = await client.transfer.create({
   *   currency: 'XOF',
   *   merchantTransactionId: 'TRANSFER-001',
   *   phoneNumber: '+2250707000001',
   *   amount: 500,
   *   paymentMethod: 'OM_CI',
   *   reason: 'Remboursement client',
   *   notifyUrl: 'https://monsite.com/webhook',
   * }, 'CI')
   * ```
   */
  async create(
    request: TransferRequest,
    country: string,
  ): Promise<TransferResponse> {
    validateTransferRequest(request)
    const auth = this.resolveAuthenticator(country)
    const body = serializeTransferRequest(request)

    try {
      const token = await auth.getToken()
      const raw = await this.httpClient.post<Record<string, unknown>>(
        '/v1/transfer',
        body,
        token,
      )
      return toTransferResponse(raw)
    } catch (error) {
      if (error instanceof ApiError && this.isTokenExpired(error)) {
        const token = await auth.forceRefresh()
        const raw = await this.httpClient.post<Record<string, unknown>>(
          '/v1/transfer',
          body,
          token,
        )
        return toTransferResponse(raw)
      }
      throw error
    }
  }

  /**
   * Récupère le statut actuel d'un transfert.
   *
   * @param transactionId - Identifiant de la transaction CinetPay ou `merchant_transaction_id`
   * @param country - Code pays ISO (ex: 'CI', 'SN')
   * @returns Statut du transfert avec les informations du bénéficiaire
   * @throws {ApiError} Si la transaction n'est pas trouvée (NOT_FOUND)
   *
   * @example
   * ```typescript
   * const status = await client.transfer.getStatus('dc1f6d3d-...', 'CI')
   * if (status.status === 'SUCCESS') {
   *   console.log(`Transféré ${status.amount} ${status.currency}`)
   * }
   * ```
   */
  async getStatus(
    transactionId: string,
    country: string,
  ): Promise<TransferStatus> {
    const auth = this.resolveAuthenticator(country)

    try {
      const token = await auth.getToken()
      const raw = await this.httpClient.get<Record<string, unknown>>(
        `/v1/transfer/${encodeURIComponent(transactionId)}`,
        token,
      )
      return toTransferStatus(raw)
    } catch (error) {
      if (error instanceof ApiError && this.isTokenExpired(error)) {
        const token = await auth.forceRefresh()
        const raw = await this.httpClient.get<Record<string, unknown>>(
          `/v1/transfer/${encodeURIComponent(transactionId)}`,
          token,
        )
        return toTransferStatus(raw)
      }
      throw error
    }
  }

  private resolveAuthenticator(country: string): Authenticator {
    const key = country.toUpperCase()
    const auth = this.authenticators.get(key)
    if (!auth) {
      throw new TypeError(
        `No credentials configured for country "${key}". Available: ${[...this.authenticators.keys()].join(', ')}`,
      )
    }
    return auth
  }

  private isTokenExpired(error: ApiError): boolean {
    return error.apiCode === 1003 || error.apiStatus === 'EXPIRED_TOKEN'
  }
}
