import type { PaymentRequest } from './types/payment'
import type { TransferRequest } from './types/transfer'
import { CURRENCIES, type Currency } from './constants/currencies'
import { CHANNELS, type Channel } from './constants/channels'
import { PAYMENT_METHODS, type PaymentMethod } from './constants/payment-methods'

// ────────────────────────────────────────────
// Helpers
// ────────────────────────────────────────────

class ValidationError extends TypeError {
  constructor(field: string, message: string) {
    super(`[${field}] ${message}`)
    this.name = 'ValidationError'
  }
}

const CURRENCY_VALUES = new Set(Object.values(CURRENCIES))
const CHANNEL_VALUES = new Set(Object.values(CHANNELS))
const PAYMENT_METHOD_VALUES = new Set(Object.values(PAYMENT_METHODS))
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
const PHONE_REGEX = /^\+\d{8,15}$/
const OTP_REGEX = /^\d{4,6}$/

function assertString(field: string, value: unknown, min: number, max: number): asserts value is string {
  if (typeof value !== 'string' || value.length < min || value.length > max) {
    throw new ValidationError(field, `must be a string between ${min} and ${max} characters (got ${typeof value === 'string' ? value.length : typeof value})`)
  }
}

function assertEnum<T extends string>(field: string, value: unknown, allowed: Set<T>): asserts value is T {
  if (!allowed.has(value as T)) {
    throw new ValidationError(field, `must be one of: ${[...allowed].join(', ')} (got "${value}")`)
  }
}

function assertAmount(field: string, value: unknown, min: number, max: number): asserts value is number {
  if (typeof value !== 'number' || !Number.isInteger(value) || value < min || value > max) {
    throw new ValidationError(field, `must be an integer between ${min} and ${max} (got ${value})`)
  }
}

function assertUrl(field: string, value: unknown, maxLength: number): void {
  assertString(field, value, 1, maxLength)
  if (!(value as string).startsWith('http://') && !(value as string).startsWith('https://')) {
    throw new ValidationError(field, `must be a valid URL starting with http:// or https://`)
  }
}

function assertEmail(field: string, value: unknown): void {
  if (typeof value !== 'string' || !EMAIL_REGEX.test(value)) {
    throw new ValidationError(field, `must be a valid email address (got "${value}")`)
  }
}

function assertPhone(field: string, value: string): void {
  if (!PHONE_REGEX.test(value)) {
    throw new ValidationError(field, `must be in international format +XXXXXXXXXXXX (got "${value}")`)
  }
}

// ────────────────────────────────────────────
// Payment validation
// ────────────────────────────────────────────

/**
 * Valide un PaymentRequest avant envoi à l'API.
 * Lève une TypeError descriptive si un champ est invalide.
 * @internal
 */
export function validatePaymentRequest(req: PaymentRequest): void {
  assertEnum('currency', req.currency, CURRENCY_VALUES as Set<Currency>)
  assertString('merchantTransactionId', req.merchantTransactionId, 1, 30)
  assertAmount('amount', req.amount, 100, 2_500_000)
  assertEnum('lang', req.lang, new Set(['fr', 'en'] as const))
  assertString('designation', req.designation, 1, 255)
  assertEmail('clientEmail', req.clientEmail)
  assertString('clientFirstName', req.clientFirstName, 2, 255)
  assertString('clientLastName', req.clientLastName, 2, 255)
  assertUrl('successUrl', req.successUrl, 120)
  assertUrl('failedUrl', req.failedUrl, 120)
  assertUrl('notifyUrl', req.notifyUrl, 120)
  assertEnum('channel', req.channel, CHANNEL_VALUES as Set<Channel>)

  if (req.paymentMethod !== undefined) {
    assertEnum('paymentMethod', req.paymentMethod, PAYMENT_METHOD_VALUES as Set<PaymentMethod>)
  }

  if (req.clientPhoneNumber !== undefined) {
    assertPhone('clientPhoneNumber', req.clientPhoneNumber)
  }

  if (req.otpCode !== undefined) {
    if (typeof req.otpCode !== 'string' || !OTP_REGEX.test(req.otpCode)) {
      throw new ValidationError('otpCode', 'must be 4 to 6 digits')
    }
  }

  // Direct pay requires phoneNumber and paymentMethod
  if (req.directPay === true) {
    if (!req.clientPhoneNumber) {
      throw new ValidationError('clientPhoneNumber', 'is required when directPay is true')
    }
    if (!req.paymentMethod) {
      throw new ValidationError('paymentMethod', 'is required when directPay is true')
    }
  }
}

// ────────────────────────────────────────────
// Transfer validation
// ────────────────────────────────────────────

/**
 * Valide un TransferRequest avant envoi à l'API.
 * Lève une TypeError descriptive si un champ est invalide.
 * @internal
 */
export function validateTransferRequest(req: TransferRequest): void {
  assertEnum('currency', req.currency, CURRENCY_VALUES as Set<Currency>)
  assertString('merchantTransactionId', req.merchantTransactionId, 1, 30)
  assertAmount('amount', req.amount, 100, 1_500_000)
  assertEnum('paymentMethod', req.paymentMethod, PAYMENT_METHOD_VALUES as Set<PaymentMethod>)
  assertString('reason', req.reason, 1, 255)
  assertUrl('notifyUrl', req.notifyUrl, 120)
  assertPhone('phoneNumber', req.phoneNumber)
}

export { ValidationError }
