import type { HttpClient } from '../http/http-client'
import type { Authenticator } from '../auth/authenticator'
import type { Balance } from '../types/balance'
import { toBalance } from '../types/balance'
import { ApiError } from '../errors/api-error'

/**
 * API de consultation du solde du compte marchand CinetPay.
 *
 * @example
 * ```typescript
 * // Accessible via client.balance
 * const balance = await client.balance.get('CI')
 * console.log(balance.availableBalance) // "249711.74"
 * ```
 */
export class BalanceApi {
  constructor(
    private readonly httpClient: HttpClient,
    private readonly authenticators: Map<string, Authenticator>,
  ) {}

  /**
   * Récupère le solde disponible du compte marchand pour un pays donné.
   * Ce solde est celui utilisé pour les opérations de transfert.
   *
   * @param country - Code pays ISO (ex: 'CI', 'SN') — détermine les credentials utilisés
   * @returns Solde disponible avec la devise du compte
   * @throws {ApiError} Si l'authentification échoue
   * @throws {TypeError} Si le pays n'est pas configuré dans les credentials
   *
   * @example
   * ```typescript
   * const balance = await client.balance.get('CI')
   * console.log(`${balance.availableBalance} ${balance.currency}`)
   * // "249711.74 XOF"
   * ```
   */
  async get(country: string): Promise<Balance> {
    const auth = this.resolveAuthenticator(country)

    try {
      const token = await auth.getToken()
      const raw = await this.httpClient.get<Record<string, unknown>>(
        '/v1/balances',
        token,
      )
      return toBalance(raw)
    } catch (error) {
      if (error instanceof ApiError && this.isTokenExpired(error)) {
        const token = await auth.forceRefresh()
        const raw = await this.httpClient.get<Record<string, unknown>>(
          '/v1/balances',
          token,
        )
        return toBalance(raw)
      }
      throw error
    }
  }

  private resolveAuthenticator(country: string): Authenticator {
    const key = country.toUpperCase()
    const auth = this.authenticators.get(key)
    if (!auth) {
      throw new TypeError(
        `No credentials configured for country "${key}". Available: ${[...this.authenticators.keys()].join(', ')}`,
      )
    }
    return auth
  }

  private isTokenExpired(error: ApiError): boolean {
    return error.apiCode === 1003 || error.apiStatus === 'EXPIRED_TOKEN'
  }
}
