import type { Currency } from '../constants/currencies'

/** Solde du compte marchand retourné par `client.balance.get()` */
export interface Balance {
  /** Code HTTP de la réponse API */
  code: number
  /** Statut textuel de la réponse */
  status: string
  /** Solde disponible du compte marchand (utilisé pour les transferts) */
  availableBalance: string
  /** Devise du compte */
  currency: Currency
}

/** @internal Transforme la réponse brute API en Balance typé */
export function toBalance(raw: Record<string, unknown>): Balance {
  return {
    code: raw.code as number,
    status: raw.status as string,
    availableBalance: raw.available_balance as string,
    currency: raw.currency as Currency,
  }
}
