/**
 * URL de base par défaut de l'API CinetPay (environnement **Sandbox**).
 * Pour la production, utilisez `https://api.cinetpay.co`.
 */
export const DEFAULT_BASE_URL = 'https://api.cinetpay.net'

/** URL de l'API CinetPay en production */
export const PRODUCTION_BASE_URL = 'https://api.cinetpay.co'

/** Préfixe des clés API sandbox */
export const API_KEY_PREFIX_TEST = 'sk_test_'

/** Préfixe des clés API production */
export const API_KEY_PREFIX_LIVE = 'sk_live_'

/** TTL par défaut du cache token : 23h (marge de sécurité sous les 86400s de l'API) */
export const DEFAULT_TOKEN_TTL = 82800

/** Timeout par défaut des requêtes HTTP en millisecondes */
export const DEFAULT_TIMEOUT = 30_000

/** Identifiants API pour un pays donné */
export interface CountryCredentials {
  /**
   * Clé API fournie par CinetPay pour ce pays.
   * - Sandbox : commence par `sk_test_`
   * - Production : commence par `sk_live_`
   */
  apiKey: string
  /** Mot de passe API fourni par CinetPay pour ce pays */
  apiPassword: string
}

/**
 * Interface pour le stockage des tokens JWT.
 * Implémentez cette interface pour utiliser Redis, localStorage, ou tout autre backend.
 *
 * @example
 * ```typescript
 * class RedisTokenStore implements TokenStore {
 *   async get(key: string) { return redis.get(key) }
 *   async set(key: string, value: string, ttl: number) { await redis.setex(key, ttl, value) }
 *   async delete(key: string) { await redis.del(key) }
 * }
 * ```
 */
export interface TokenStore {
  /** Récupère un token depuis le cache. Retourne `null` si absent ou expiré. */
  get(key: string): string | null | Promise<string | null>
  /** Stocke un token avec un TTL en secondes. */
  set(key: string, value: string, ttlSeconds: number): void | Promise<void>
  /** Supprime un token du cache. */
  delete(key: string): void | Promise<void>
}

/**
 * Configuration du client CinetPay.
 *
 * @example
 * ```typescript
 * const config: ClientConfig = {
 *   credentials: {
 *     CI: { apiKey: process.env.KEY_CI!, apiPassword: process.env.PASS_CI! },
 *     SN: { apiKey: process.env.KEY_SN!, apiPassword: process.env.PASS_SN! },
 *   },
 * }
 * ```
 */
export interface ClientConfig {
  /**
   * Credentials par code pays ISO 3166-1 alpha-2.
   * Chaque pays CinetPay nécessite ses propres identifiants API.
   *
   * @example `{ CI: { apiKey: '...', apiPassword: '...' }, SN: { apiKey: '...', apiPassword: '...' } }`
   */
  credentials: Record<string, CountryCredentials>

  /**
   * URL de base de l'API CinetPay. Doit utiliser HTTPS (sauf localhost).
   * - Sandbox : `https://api.cinetpay.net` (clés `sk_test_...`)
   * - Production : `https://api.cinetpay.co` (clés `sk_live_...`)
   *
   * Si omis, le SDK détecte automatiquement l'environnement à partir
   * du préfixe des clés API : `sk_test_` → sandbox, `sk_live_` → production.
   * @default Auto-détecté depuis les clés API
   */
  baseUrl?: string

  /**
   * Durée de cache du token JWT en secondes.
   * @default 82800 (23 heures)
   */
  tokenTtl?: number

  /**
   * Store personnalisé pour le cache des tokens JWT.
   * @default MemoryTokenStore (en mémoire)
   */
  tokenStore?: TokenStore

  /**
   * Timeout des requêtes HTTP en millisecondes.
   * @default 30000
   */
  timeout?: number

  /**
   * Active le logging en console avec le préfixe `[cinetpay]`.
   * Raccourci pour `logger: new ConsoleLogger()`.
   * @default false
   */
  debug?: boolean

  /**
   * Logger personnalisé. Prend priorité sur `debug`.
   * Implémentez l'interface `Logger` pour brancher Winston, Pino, etc.
   * @default NoopLogger (silencieux)
   */
  logger?: import('../logger').Logger

  /**
   * Force la résolution DNS en IPv4 pour toutes les requêtes du SDK.
   * Résout les problèmes de connectivité sur les serveurs où l'IPv6 est mal configuré.
   * Équivalent de `force_ip_resolve => 'v4'` dans Guzzle (PHP).
   *
   * **Node.js uniquement** — ignoré dans les navigateurs, Deno et Bun.
   * Utilise `dns.setDefaultResultOrder('ipv4first')` au niveau du process.
   *
   * @default false
   */
  forceIPv4?: boolean
}
