import type { HttpClient } from '../http/http-client'
import type { Authenticator } from '../auth/authenticator'
import type {
  PaymentRequest,
  PaymentResponse,
  PaymentStatus,
} from '../types/payment'
import {
  serializePaymentRequest,
  toPaymentResponse,
  toPaymentStatus,
} from '../types/payment'
import { ApiError } from '../errors/api-error'
import { validatePaymentRequest } from '../validation'

/**
 * API de paiement web CinetPay.
 * Permet d'initialiser des paiements et de vérifier leur statut.
 *
 * @example
 * ```typescript
 * // Accessible via client.payment
 * const payment = await client.payment.initialize(request, 'CI')
 * const status = await client.payment.getStatus(payment.paymentToken, 'CI')
 * ```
 */
export class PaymentApi {
  constructor(
    private readonly httpClient: HttpClient,
    private readonly authenticators: Map<string, Authenticator>,
  ) {}

  /**
   * Initialise une transaction de paiement web.
   *
   * @param request - Paramètres du paiement (montant, devise, URLs, client, etc.)
   * @param country - Code pays ISO (ex: 'CI', 'SN') — détermine les credentials utilisés
   * @returns Réponse contenant le `paymentUrl` (redirection) et le `paymentToken` (vérification)
   * @throws {ApiError} Si l'API retourne une erreur (ex: TRANSACTION_EXIST, INVALID_PARAMS)
   * @throws {TypeError} Si le pays n'est pas configuré dans les credentials
   *
   * @example
   * ```typescript
   * const payment = await client.payment.initialize({
   *   currency: 'XOF',
   *   merchantTransactionId: 'ORDER-001',
   *   amount: 1000,
   *   lang: 'fr',
   *   designation: 'Achat en ligne',
   *   clientEmail: 'client@email.com',
   *   clientFirstName: 'Jean',
   *   clientLastName: 'Dupont',
   *   successUrl: 'https://monsite.com/success',
   *   failedUrl: 'https://monsite.com/failed',
   *   notifyUrl: 'https://monsite.com/webhook',
   *   channel: 'PUSH',
   * }, 'CI')
   *
   * // Rediriger le client si nécessaire
   * if (payment.details.mustBeRedirected) {
   *   redirect(payment.paymentUrl)
   * }
   * ```
   */
  async initialize(
    request: PaymentRequest,
    country: string,
  ): Promise<PaymentResponse> {
    validatePaymentRequest(request)
    const auth = this.resolveAuthenticator(country)
    const body = serializePaymentRequest(request)

    try {
      const token = await auth.getToken()
      const raw = await this.httpClient.post<Record<string, unknown>>(
        '/v1/payment',
        body,
        token,
      )
      return toPaymentResponse(raw)
    } catch (error) {
      if (error instanceof ApiError && this.isTokenExpired(error)) {
        const token = await auth.forceRefresh()
        const raw = await this.httpClient.post<Record<string, unknown>>(
          '/v1/payment',
          body,
          token,
        )
        return toPaymentResponse(raw)
      }
      throw error
    }
  }

  /**
   * Récupère le statut actuel d'un paiement.
   *
   * @param identifier - `payment_token`, `transaction_id` ou `merchant_transaction_id`
   * @param country - Code pays ISO (ex: 'CI', 'SN')
   * @returns Statut de la transaction avec les informations utilisateur
   * @throws {ApiError} Si la transaction n'est pas trouvée (NOT_FOUND)
   *
   * @example
   * ```typescript
   * const status = await client.payment.getStatus('ORDER-001', 'CI')
   * if (status.status === 'SUCCESS') {
   *   // Paiement confirmé
   * }
   * ```
   */
  async getStatus(
    identifier: string,
    country: string,
  ): Promise<PaymentStatus> {
    const auth = this.resolveAuthenticator(country)

    try {
      const token = await auth.getToken()
      const raw = await this.httpClient.get<Record<string, unknown>>(
        `/v1/payment/${encodeURIComponent(identifier)}`,
        token,
      )
      return toPaymentStatus(raw)
    } catch (error) {
      if (error instanceof ApiError && this.isTokenExpired(error)) {
        const token = await auth.forceRefresh()
        const raw = await this.httpClient.get<Record<string, unknown>>(
          `/v1/payment/${encodeURIComponent(identifier)}`,
          token,
        )
        return toPaymentStatus(raw)
      }
      throw error
    }
  }

  private resolveAuthenticator(country: string): Authenticator {
    const key = country.toUpperCase()
    const auth = this.authenticators.get(key)
    if (!auth) {
      throw new TypeError(
        `No credentials configured for country "${key}". Available: ${[...this.authenticators.keys()].join(', ')}`,
      )
    }
    return auth
  }

  private isTokenExpired(error: ApiError): boolean {
    return error.apiCode === 1003 || error.apiStatus === 'EXPIRED_TOKEN'
  }
}
