import type { ClientConfig } from './types/config'
import {
  DEFAULT_BASE_URL,
  DEFAULT_TOKEN_TTL,
  DEFAULT_TIMEOUT,
  PRODUCTION_BASE_URL,
  API_KEY_PREFIX_TEST,
  API_KEY_PREFIX_LIVE,
} from './types/config'
import { HttpClient } from './http/http-client'
import { Authenticator } from './auth/authenticator'
import { MemoryTokenStore } from './auth/token-store'
import { PaymentApi } from './api/payment'
import { TransferApi } from './api/transfer'
import { BalanceApi } from './api/balance'
import { ConsoleLogger, NoopLogger } from './logger'
import type { Logger } from './logger'

/**
 * Client principal du SDK CinetPay.
 * Gère l'authentification multi-pays, le cache de tokens JWT,
 * et expose les APIs de paiement, transfert et solde.
 *
 * @example
 * ```typescript
 * import { CinetPayClient } from 'cinetpay-js'
 *
 * const client = new CinetPayClient({
 *   credentials: {
 *     CI: { apiKey: process.env.KEY_CI!, apiPassword: process.env.PASS_CI! },
 *     SN: { apiKey: process.env.KEY_SN!, apiPassword: process.env.PASS_SN! },
 *   },
 *   debug: true, // Active les logs en console
 * })
 * ```
 */
export class CinetPayClient {
  /** API de paiement web — initialisation et vérification de statut */
  readonly payment: PaymentApi
  /** API de transfert d'argent — envoi et vérification de statut */
  readonly transfer: TransferApi
  /** API de consultation du solde du compte marchand */
  readonly balance: BalanceApi

  private readonly authenticators: Map<string, Authenticator>

  /**
   * Crée un nouveau client CinetPay.
   *
   * @param config - Configuration avec les credentials par pays
   * @throws {TypeError} Si aucun credential n'est fourni
   * @throws {TypeError} Si le baseUrl n'utilise pas HTTPS (sauf localhost)
   */
  constructor(config: ClientConfig) {
    const entries = Object.entries(config.credentials)
    if (entries.length === 0) {
      throw new TypeError(
        'At least one country credential must be provided in config.credentials',
      )
    }

    const tokenTtl = config.tokenTtl ?? DEFAULT_TOKEN_TTL
    const timeout = config.timeout ?? DEFAULT_TIMEOUT
    const tokenStore = config.tokenStore ?? new MemoryTokenStore()

    // Resolve logger: explicit logger > debug flag > silent
    const logger: Logger = config.logger ?? (config.debug ? new ConsoleLogger() : new NoopLogger())

    // Detect environment from API key prefixes
    const detectedEnv = this.detectEnvironment(entries, logger)

    // Resolve baseUrl: explicit config > auto-detect from keys > sandbox default
    const baseUrl = config.baseUrl ?? (detectedEnv === 'live' ? PRODUCTION_BASE_URL : DEFAULT_BASE_URL)

    // Validate key/baseUrl coherence
    this.validateKeyUrlCoherence(detectedEnv, baseUrl, logger)

    // Enforce HTTPS in production
    if (!baseUrl.startsWith('https://') && !baseUrl.includes('localhost') && !baseUrl.includes('127.0.0.1')) {
      throw new TypeError(
        'baseUrl must use HTTPS for security. Use https:// or localhost for development.',
      )
    }

    // SSRF protection: only allow CinetPay domains or localhost for development
    const ALLOWED_HOSTS = [
      'api.cinetpay.net',   // Sandbox
      'api.cinetpay.co',    // Production
      'localhost',
      '127.0.0.1',
    ]
    try {
      const url = new URL(baseUrl)
      if (!ALLOWED_HOSTS.some((h) => url.hostname === h || url.hostname.endsWith(`.${h}`))) {
        logger.warn(
          `baseUrl hostname "${url.hostname}" is not a known CinetPay domain. ` +
          `Expected: ${ALLOWED_HOSTS.join(', ')}. Proceeding anyway.`,
        )
      }
    } catch {
      throw new TypeError(`baseUrl "${baseUrl}" is not a valid URL.`)
    }

    // Warn if running in a browser context
    if (typeof globalThis.window !== 'undefined' && typeof globalThis.document !== 'undefined') {
      logger.warn(
        'Running in a browser environment. ' +
        'API credentials (api_key/api_password) will be exposed in client-side code. ' +
        'Use this SDK server-side only (Node.js, Deno, Bun) or via a backend proxy.',
      )
    }

    // Force IPv4 DNS resolution (Node.js only)
    if (config.forceIPv4) {
      this.applyIPv4(logger)
    }

    const httpClient = new HttpClient(baseUrl, timeout, logger)

    this.authenticators = new Map()
    for (const [country, credentials] of entries) {
      const key = country.toUpperCase()
      this.authenticators.set(
        key,
        new Authenticator(httpClient, key, credentials, tokenTtl, tokenStore, logger),
      )
    }

    this.payment = new PaymentApi(httpClient, this.authenticators)
    this.transfer = new TransferApi(httpClient, this.authenticators)
    this.balance = new BalanceApi(httpClient, this.authenticators)

    logger.debug('CinetPayClient initialized', {
      countries: this.countries(),
      baseUrl,
      tokenTtl,
      timeout,
    })
  }

  /**
   * Retourne la liste des codes pays configurés.
   *
   * @example
   * ```typescript
   * client.countries() // ['CI', 'SN']
   * ```
   */
  countries(): string[] {
    return [...this.authenticators.keys()]
  }

  /**
   * Révoque le token JWT en cache pour un pays donné.
   * Le prochain appel API déclenchera une nouvelle authentification.
   * Utile en cas de compromission ou de rotation manuelle des credentials.
   *
   * @param country - Code pays ISO (ex: 'CI', 'SN')
   * @throws {TypeError} Si le pays n'est pas configuré
   *
   * @example
   * ```typescript
   * await client.revokeToken('CI') // Force une ré-authentification au prochain appel
   * ```
   */
  async revokeToken(country: string): Promise<void> {
    const key = country.toUpperCase()
    const auth = this.authenticators.get(key)
    if (!auth) {
      throw new TypeError(
        `No credentials configured for country "${key}". Available: ${this.countries().join(', ')}`,
      )
    }
    await auth.clearCache()
  }

  /**
   * Révoque tous les tokens JWT en cache pour tous les pays configurés.
   *
   * @example
   * ```typescript
   * await client.revokeAllTokens()
   * ```
   */
  async revokeAllTokens(): Promise<void> {
    await Promise.all(
      [...this.authenticators.values()].map((auth) => auth.clearCache()),
    )
  }

  /** Empêche la fuite des credentials via JSON.stringify */
  toJSON(): Record<string, unknown> {
    return { countries: this.countries() }
  }

  /**
   * Détecte l'environnement (test/live) à partir des préfixes des clés API.
   * - `sk_test_...` → 'test' (sandbox)
   * - `sk_live_...` → 'live' (production)
   * - Mixte → warning + 'mixed'
   * - Aucun préfixe reconnu → 'unknown'
   */
  private detectEnvironment(
    entries: [string, { apiKey: string; apiPassword: string }][],
    logger: Logger,
  ): 'test' | 'live' | 'mixed' | 'unknown' {
    const envs = new Set<string>()
    for (const [country, creds] of entries) {
      if (creds.apiKey.startsWith(API_KEY_PREFIX_TEST)) {
        envs.add('test')
      } else if (creds.apiKey.startsWith(API_KEY_PREFIX_LIVE)) {
        envs.add('live')
      } else {
        logger.warn(
          `API key for country ${country.toUpperCase()} does not start with "${API_KEY_PREFIX_TEST}" or "${API_KEY_PREFIX_LIVE}". ` +
          `Expected format: sk_test_... (sandbox) or sk_live_... (production).`,
        )
        envs.add('unknown')
      }
    }

    if (envs.has('test') && envs.has('live')) {
      logger.error(
        'MIXED ENVIRONMENTS: some credentials use sk_test_ (sandbox) and others use sk_live_ (production). ' +
        'This will cause authentication failures. Use the same environment for all countries.',
      )
      return 'mixed'
    }

    if (envs.has('live')) return 'live'
    if (envs.has('test')) return 'test'
    return 'unknown'
  }

  /**
   * Vérifie la cohérence entre le type de clé API et le baseUrl.
   * - Clés `sk_test_` + baseUrl production → error
   * - Clés `sk_live_` + baseUrl sandbox → error
   */
  private validateKeyUrlCoherence(
    detectedEnv: 'test' | 'live' | 'mixed' | 'unknown',
    baseUrl: string,
    logger: Logger,
  ): void {
    const isSandboxUrl = baseUrl.includes('cinetpay.net')
    const isProductionUrl = baseUrl.includes('cinetpay.co')

    if (detectedEnv === 'live' && isSandboxUrl) {
      logger.error(
        `ENVIRONMENT MISMATCH: production keys (sk_live_) are used with sandbox URL (${baseUrl}). ` +
        `Use baseUrl: "${PRODUCTION_BASE_URL}" for production, or remove baseUrl to auto-detect.`,
      )
    }
    if (detectedEnv === 'test' && isProductionUrl) {
      logger.error(
        `ENVIRONMENT MISMATCH: sandbox keys (sk_test_) are used with production URL (${baseUrl}). ` +
        `Use baseUrl: "${DEFAULT_BASE_URL}" for sandbox, or remove baseUrl to auto-detect.`,
      )
    }
  }

  /**
   * Force la résolution DNS en IPv4 dans Node.js.
   * Utilise `dns.setDefaultResultOrder('ipv4first')` — disponible depuis Node.js 16.4.
   * No-op silencieux dans les environnements non-Node (navigateurs, Deno, Bun).
   */
  private applyIPv4(logger: Logger): void {
    try {
      // Dynamic import to avoid bundling node:dns in browser builds
      // eslint-disable-next-line @typescript-eslint/no-require-imports
      const dns = require('node:dns')
      if (typeof dns.setDefaultResultOrder === 'function') {
        dns.setDefaultResultOrder('ipv4first')
        logger.debug('DNS resolution forced to IPv4')
      } else {
        logger.warn('forceIPv4: dns.setDefaultResultOrder not available in this Node.js version')
      }
    } catch {
      // Not in Node.js (browser, Deno, Bun) — silently ignore
      logger.debug('forceIPv4: not in Node.js, option ignored')
    }
  }
}
