import type { CountryCredentials, TokenStore } from '../types/config'
import type { HttpClient } from '../http/http-client'
import type { Logger } from '../logger'
import { AuthenticationError } from '../errors/authentication-error'

/** @internal Réponse brute de l'endpoint d'authentification */
interface AuthResponse {
  /** Code HTTP (200 = succès) */
  code: number
  /** Statut textuel (OK, INVALID_CREDENTIALS) */
  status: string
  /** Token JWT à utiliser dans les requêtes suivantes */
  access_token: string
  /** Type de token (toujours "bearer") */
  token_type: string
  /** Durée de validité en secondes (86400 = 24h) */
  expires_in: number
}

/**
 * Gère l'authentification JWT pour un pays donné.
 *
 * Chaque pays CinetPay a ses propres credentials (`api_key` / `api_password`).
 * L'Authenticator obtient un token JWT via `POST /v1/oauth/login`,
 * le met en cache dans le {@link TokenStore}, et le renouvelle automatiquement
 * quand il expire.
 *
 * Les credentials sont stockés dans des champs privés ES2022 (`#apiKey`, `#apiPassword`)
 * et ne sont jamais exposés via `JSON.stringify()`, `Object.keys()` ou `console.log()`.
 *
 * @internal Utilisé en interne par {@link CinetPayClient}. Ne pas instancier directement.
 */
export class Authenticator {
  /** Clé utilisée dans le TokenStore pour isoler le token de ce pays */
  private readonly cacheKey: string
  private readonly httpClient: HttpClient
  private readonly country: string
  private readonly tokenTtl: number
  private readonly tokenStore: TokenStore
  private readonly logger: Logger

  /** Credentials stockés en champs privés ES2022 — invisibles à la sérialisation */
  #apiKey: string
  #apiPassword: string

  /** Promise en cours pour éviter les appels auth simultanés (token stampede) */
  #pendingAuth: Promise<string> | null = null

  /**
   * @param httpClient - Client HTTP partagé entre toutes les APIs
   * @param country - Code pays ISO en majuscules (ex: 'CI', 'SN')
   * @param credentials - Couple `apiKey` / `apiPassword` pour ce pays
   * @param tokenTtl - Durée de cache du token en secondes (défaut: 82800 = 23h)
   * @param tokenStore - Backend de cache (MemoryTokenStore par défaut)
   * @param logger - Logger pour le debug et les avertissements
   */
  constructor(
    httpClient: HttpClient,
    country: string,
    credentials: CountryCredentials,
    tokenTtl: number,
    tokenStore: TokenStore,
    logger: Logger,
  ) {
    this.httpClient = httpClient
    this.country = country
    this.tokenTtl = tokenTtl
    this.tokenStore = tokenStore
    this.logger = logger
    this.cacheKey = `cinetpay_token_${country.toLowerCase()}`

    this.#apiKey = credentials.apiKey
    this.#apiPassword = credentials.apiPassword
  }

  /**
   * Récupère un token JWT valide.
   * Retourne le token en cache s'il est encore valide,
   * sinon appelle l'API d'authentification.
   *
   * Utilise le promise coalescing pour éviter les appels simultanés
   * (token stampede) : si N requêtes arrivent en même temps avec un cache vide,
   * un seul appel auth est effectué et les N requêtes partagent la même promise.
   *
   * @returns Token JWT Bearer
   * @throws {AuthenticationError} Si l'API ne retourne pas de token
   */
  async getToken(): Promise<string> {
    const cached = await this.tokenStore.get(this.cacheKey)
    if (cached) {
      this.logger.debug(`Token cache hit for ${this.country}`)
      return cached
    }
    this.logger.debug(`Token cache miss for ${this.country}, authenticating...`)

    // Promise coalescing : réutilise l'appel en cours s'il existe
    if (!this.#pendingAuth) {
      this.#pendingAuth = this.authenticate().finally(() => {
        this.#pendingAuth = null
      })
    } else {
      this.logger.debug(`Reusing pending auth for ${this.country} (coalesced)`)
    }
    return this.#pendingAuth
  }

  /**
   * Force le renouvellement du token (supprime le cache puis ré-authentifie).
   * Appelé automatiquement par les APIs quand l'API retourne EXPIRED_TOKEN (1003).
   *
   * @returns Nouveau token JWT
   * @throws {AuthenticationError} Si l'API ne retourne pas de token
   */
  async forceRefresh(): Promise<string> {
    this.logger.warn(`Force refreshing token for ${this.country} (expired or invalid)`)
    await this.tokenStore.delete(this.cacheKey)
    return this.authenticate()
  }

  /**
   * Supprime le token en cache pour ce pays.
   * Utile pour forcer une ré-authentification au prochain appel.
   */
  async clearCache(): Promise<void> {
    await this.tokenStore.delete(this.cacheKey)
  }

  /**
   * Empêche la fuite des credentials dans `JSON.stringify()`.
   * Retourne uniquement le pays et la clé de cache.
   */
  toJSON(): Record<string, unknown> {
    return { country: this.country, cacheKey: this.cacheKey }
  }

  /**
   * Appelle `POST /v1/oauth/login` avec les credentials du pays
   * et stocke le token reçu dans le cache.
   *
   * @returns Token JWT
   * @throws {AuthenticationError} Si la réponse ne contient pas `access_token`
   */
  private async authenticate(): Promise<string> {
    let data: AuthResponse
    try {
      data = await this.httpClient.post<AuthResponse>('/v1/oauth/login', {
        api_key: this.#apiKey,
        api_password: this.#apiPassword,
      })
    } catch (error) {
      // Sanitise error message to prevent credential leakage in stack traces
      throw new AuthenticationError(
        `Authentication failed for country ${this.country}`,
      )
    }

    if (!data.access_token) {
      throw new AuthenticationError(
        `Authentication failed for country ${this.country}: no access_token in response`,
      )
    }

    await this.tokenStore.set(this.cacheKey, data.access_token, this.tokenTtl)
    this.logger.debug(`Token cached for ${this.country} (TTL: ${this.tokenTtl}s)`)
    return data.access_token
  }
}
